let mensajeActual = 0;

function mostrarMensajeFinal(indice) {

    mensajeActual = indice;

    const datos = mensajesFinales[indice];

    const ventana = document.createElement("div");

    ventana.className = "ventanaXP ventanaMensajeFinal";

    ventana.innerHTML = `

    <div class="barraTitulo">

        ${datos.titulo}

    </div>

    <div class="contenidoMensajeFinal">

        <p>

            ${datos.texto}

        </p>

        <button id="btnFinal">

            ${datos.boton}

        </button>

    </div>

    `;

    document.body.appendChild(ventana);

    document.getElementById("btnFinal").onclick = siguienteMensaje;

}

function siguienteMensaje() {

    document.querySelector(".ventanaMensajeFinal").remove();

    if (mensajeActual < 2) {

        mostrarMensajeFinal(mensajeActual + 1);

    } else {

        reiniciarSistema();

    }

}
function reiniciarSistema() {

    document.body.innerHTML = `

    <div id="pantallaRecuperacion">

        <pre>

Shutting down...

Saving memories...

Restarting system...

        </pre>

    </div>

    `;

    setTimeout(() => {

        location.reload();

    }, 2500);

}


function pantallaRecuperacion() {
    document.body.style.background = "black";
    document.body.style.margin = "0";
    document.body.style.overflow = "hidden";

    document.body.innerHTML = `

    <div id="pantallaRecuperacion">

        <pre id="terminalRecuperacion"></pre>

    </div>

    `;

    iniciarRecuperacion();

}

function iniciarRecuperacion() {

    const terminal = document.getElementById("terminalRecuperacion");

    let i = 0;

    const intervalo = setInterval(() => {

        terminal.innerHTML += lineasSistema[i] + "\n";

        terminal.scrollTop = terminal.scrollHeight;

        i++;

        if (i >= lineasSistema.length) {

            clearInterval(intervalo);

            setTimeout(() => {

                ultimoTramo();

            }, 1000);

        }

    }, 250);

}


function crearFondoFinal() {

    document.body.style.background = "";
    document.body.style.backgroundColor = "";
    document.body.style.backgroundImage = "url('fotos/fondo/laminal2.jpg')";
    document.body.style.backgroundSize = "cover";
    document.body.style.backgroundPosition = "center";
    document.body.style.backgroundRepeat = "no-repeat";

    document.body.style.overflow = "hidden";

}

function ultimoTramo() {

    const pantalla = document.getElementById("pantallaRecuperacion");

    pantalla.style.transition = "opacity .8s";

    pantalla.style.opacity = "0";

    setTimeout(() => {

        pantalla.remove();

        crearFondoFinal();


        mostrarMensajeFinal(0);
        setTimeout(() => {

            iniciarFotosFinales();

        }, 500);

    }, 800);

}

let intervaloFotosFinal;
function iniciarFotosFinales() {

    intervaloFotosFinal = setInterval(() => {

        mostrarFotoFinal();

    }, 1200);

}

function mostrarFotoFinal() {

    const foto = fotosFinales[Math.floor(Math.random() * fotosFinales.length)];

    const ventana = document.createElement("div");

    ventana.className = "fotoFinal";

    ventana.innerHTML = `

        <img src="fotos/final/${foto}">

    `;

    ventana.style.left =
        Math.random() * (window.innerWidth - 220) + "px";

    ventana.style.top =
        Math.random() * (window.innerHeight - 220) + "px";

    ventana.style.transform =
        `rotate(${Math.random() * 20 - 10}deg)`;

    document.body.appendChild(ventana);

}
